import{_ as p,o as e,c as a,j as r,a as t,a1 as n}from"./chunks/framework.Bp7r_-XI.js";const m=JSON.parse('{"title":"蓝银草","description":"","frontmatter":{},"headers":[],"relativePath":"4.资源分区/1.血统与训练/1.生理类/蓝银草.md","filePath":"4.资源分区/1.血统与训练/1.生理类/蓝银草.md"}'),s={name:"4.资源分区/1.血统与训练/1.生理类/蓝银草.md"};function o(d,b,l,_,i,c){return e(),a("div",null,[...b[0]||(b[0]=[r("h1",{id:"蓝银草",tabindex:"-1"},[t("蓝银草 "),r("a",{class:"header-anchor",href:"#蓝银草","aria-label":'Permalink to "蓝银草"'},"​")],-1),r("table",{class:"bannerparthead"},[r("tbody",null,[r("tr",{id:"hdr"},[r("td",{class:"runninghead",nowrap:""},"TMD：新世短歌038")])])],-1),n('<h1 id="蓝银草武魂" tabindex="-1">蓝银草武魂 <a class="header-anchor" href="#蓝银草武魂" aria-label="Permalink to &quot;蓝银草武魂&quot;">​</a></h1><p>蓝银草武魂<br> 血统<br> 特异本质</p><p>从某个人均密度小于氢气的世界获取的特殊资源，其中标注可用XP购买的资源视作技艺<br> 特别的，轮回者必须按照顺序依次购买下述资源</p><p>【第一魂技】<br> D+600<br> 【魂力入门】<br> 你开启【魂力】能量池，关键属性为【感知+耐力】，这是一个内力亚种能量池，恢复方法包含：<br> 1.每次短休息，进行一次关键属性检定，恢复出目数的魂力，<br> 2.每次长休息，立刻回满能量池。</p><p>【武魂·蓝银草】<br> 你习得一种全新的攻击方式，使用【智力+器用+器用下属专业：蓝银草+辅助专业：植物学（学识）】进行攻击，对15m范围内的任一敌方目标造成伤害，伤害类型为钝击伤害，表现为你身上浮现蓝银草的图腾，并从图腾中生长出蓝色中心有银线的杂草抽击敌人。</p><p>【蓝银缠绕】<br> 吸收了曼陀罗蛇的魂环，你的蓝银草可以像蛇类一样主动缠绕、绞杀敌人。</p><p>消耗一个标准动作和2点【魂力】进行一次攻击，你将蓝银草结成鞭状，对射程范围内的某个敌人进行攻击，此次攻击附带2点不可豁免的【纠缠】不良点数。</p><p>【第二魂技】<br> D+500/10xp</p><p>【蓝银寄生】<br> 吸收了鬼藤的魂环，你的蓝银草可以更持久地缠绕在敌人身上，</p><p>以一个整轮动作，你消耗2点魂力，激活蓝银草的寄生能力，接下来一个场景你使用蓝银草的攻击方式获得以下增幅：<br> 攻击命中后，目标需以反射豁免对抗伤害出目，若你胜出，其身上会生长出不超过10体积的蓝银草妨碍行动，使目标陷入D级创伤来源的【C级困难地形】状态，持续一场景，<br> 此外，攻击命中时额外施加1点不可豁免的毒素异常点数。</p><p>【第三魂技】<br> C+1200</p><p>【蓝银王觉醒】<br> 你隐约感觉自己的蓝银草武魂没有那么简单，它远比普通的蓝银草更加修长、有灵性，<br> 你使用蓝银草专业进行的攻击检定射程提高15m，具有【法破】特性，</p><p>【蓝银蛛网】<br> 吸收了人面魔蛛的魂环，你的蓝银草可以结成细密的蛛网控制对手，</p><p>取代【蓝银缠绕】，消耗一个标准动作和4点【魂力】进行一次攻击，你将蓝银草结成网状，对射程范围内的某个敌人进行攻击，此次攻击附带等同于出目一半的【纠缠】不良点数，正常豁免，<br> 此外，敌人需以反射豁免对抗伤害出目，若失败，则敌人的【反射豁免】获得【劣化1】，这是一个C级创伤来源的效果，持续一轮，且你可以消耗一个自由动作对其进行一次拖拽，此次拖拽过程中无视体积带来的优势或劣势。</p><p>【第四魂技】<br> C+1000/20xp</p><p>【蓝银囚笼】<br> 吸收了地穴魔蛛的魂环，你的蓝银草可以从地下长出，化为锐利的地刺牢笼，</p><p>以一个整轮动作，你消耗4点魂力使以你为中心，半径为射程+60M范围的区域化为【蓝银突刺阵】场地，持续一个场景，这是一个C级环境来源的效果，场地下轮开始时生效，<br> 当任一目标持续处于【蓝银突刺阵】地形一轮后，必须以反射豁免对抗DC20，受到差值点穿刺伤害，至多4L，每个目标每轮只能受到一次该伤害。</p><p>【第五魂技】<br> B+2400</p><p>【蓝银皇觉醒】<br> 你的蓝银草武魂得到了觉醒，变化为可以统御所有蓝银草的蓝银皇，现在你使用蓝银草的技艺会更加娴熟，<br> 你使用蓝银草专业进行的攻击检定获得【8加骰】、【毁灭】特性，且可以将伤害出目转化为等量【纠缠】不良点数，正常豁免，</p><p>【蓝银霸王枪】<br> 觉醒为蓝银皇之后，以众多族人的力量凝聚成的魂环，你的蓝银草可以缠结成一把长枪投出，</p><p>取代【蓝银蛛网】，消耗一个标准动作和8点【魂力】进行一次攻击，你将蓝银草结成枪状，对以你为圆心，以射程+45m为半径，前方120°角的锥形范围内的所有敌人进行攻击，<br> 命中后，敌人需以反射豁免对抗伤害出目，若失败，则使敌人的【反射豁免】获得【劣化3】，这是一个B级创伤来源的效果，持续一轮，且你可以消耗一个自由动作对其进行一次拖拽，此次拖拽过程中无视体积带来的优势或劣势。</p><p>【第六魂技】<br> B+2000/40xp</p><p>【虚空亡妻】<br> 接受了爱人的献祭，含泪舔包后，你获得了这个魂环<br> 以一个移动动作，你大喊一声“复活吧，我的爱人！”，消耗2点魂力，你的触及范围内将会召唤出一个特殊随从【亡妻】（你可以自定义其外貌），持续一个场景</p><p>【亡妻】<br> ▓▓▓▓基本能力值 <br> ▓智力 11 ▓感知 14 ▓决心 14 <br> ▓力量 16 ▓敏捷 16 ▓耐力 14 <br> ▓风度 11 ▓操控 11 ▓沉着 11</p><p>▓▓▓▓技能 <br> ▓学识11-武学掌握11 <br> ▓器用1 <br> ▓手艺1 <br> ▓专注8-意志8</p><p>▓运动8-反射8、跳跃8<br> ▓生存8-强韧8 <br> ▓射击1 <br> ▓武技11-腿11</p><p>▓洞察1<br> ▓隐秘8-潜行8 <br> ▓表达1 <br> ▓社交1</p><p>▓▓▓▓衍生属性值 <br> ▓相貌11 <br> ▓体积5 <br> ▓速度57<br> ▓先攻3d10+27<br> ▓防御 基础15+3 <br> ▓生命值 29 <br> ▓意志力池 29<br> ▓意志32+5<br> ▓反射32+6 <br> ▓强韧30+5<br> ▓敏感范围 320 <br> ▓▓▓▓专长<br> 愤怒信徒（1—2）<br> 1级：死斗搏击<br> 你的全身视为武器伤害为3L的天生武器。<br> 2级：战争暴徒<br> 你的天生武器获得等于力量上附加成功数的武器伤害，并且在肉搏攻击时获得敏捷属性上附加成功数的高速或力量属性上附加成功数的威猛。</p><p>翩影游龙（1） <br> 此专长仅在你不着甲或者仅穿着轻甲的情况下生效 <br> 1级-轻盈如风 <br> 你的移动速度提升5米。当你具有传奇敏捷时，每点传奇敏捷额外提升2米的移动速度</p><p>至高王座（2）<br> 世上有各种类型的特殊体质，比如修行类的各种灵根、魔法类的各种元素体、武道类的各种天生剑体。这些体质往往会让有在某些方面上有着远超常人的天赋，人物选择一个专业，在专业相关检定上获得一成的加成（不包括附加成功）。<br> ▓▓▓▓攻击预设： <br> 力量16+武技11+腿11+武学掌握11+天生武器6+风度全检定2+至高王座6+连射3=69+10<br> 附加效果：高速3/威猛3+威猛2、【能量武器】（熔毁5，至多5点伤害转韧性）、【法破】<br> ▓▓▓▓防御预设： <br> 基础15+3+格挡11<br> ▓▓▓▓随从特性：<br> 【灵魂态】：该随从的生物类别为【虚体】，其天生武器具有【能量武器】、【法破】、【9加骰】、【连射】特性。</p><p>【第七魂技】<br> A+4800</p><p>【蓝银真身】<br> 获得神赐魂环之后，你可以开启武魂真身，蓝银草的血统能力进一步强化，<br> 你使用蓝银草专业进行的攻击检定获得【8加骰】、【湮灭】特性，攻击时附带等量的【纠缠】异常点数，正常豁免，</p><p>你的生命与这片大陆上的蓝银草相联系，获得A级环境来源的【复活】效果，<br> 每场影片一次，当你死亡时，你的意识转化为灵体附身在周围的杂草上，无法进行观察和移动以外的操作，具有等同于你的意志值的结构值，<br> 经过一周的时间可以复活，当结构值被击破时，复活失败。</p><p>此外，你还可以随时借助蓝银草稳定伤势，现在你的生命槽即使被严重填满也不会晕倒，<br> 你周围的蓝银草会成为你的视线，提高你对危险的反应能力，你的【反射豁免】检定获得【8加骰】。</p><p>【蓝银领域】<br> 达到武魂真身境界后，你能消耗一个标准动作，主动控制周围的蓝银草为你提供以下增幅，持续一个场景：<br> ①【伪装】：蓝银领域可以通过魂力释放幻象叠加在你身上，使你可以展现出不同的外貌和气息，这是一个B级附身来源的【伪装】效果，<br> 此外，如果将气息隐藏至最低，还可以达成隐身的效果，这是一个B级特异本质的【反侦测】效果，<br> ②【蓝银范围缠绕】：蓝银草获得进一步强化，其纠缠能力大大提升，敌人难以挣脱，你使用蓝银草攻击造成的【纠缠】不良点数升级为第四档异常点数，<br> ③【森罗万象】：蓝银草会在领域内获得强大的同化吸收能力，仅在战斗场景中时，你每轮开始时恢复1点【魂力】，该效果仍然遵循每天至多恢复能量池上限三倍的限制，<br> ④【海纳百川】：蓝银草会将领域内的其他生命力传递给你，你获得【生息】效果。</p><p>【第八魂技】<br> A+4000/80xp</p><p>【蓝银邪魔镜之灭】<br> 吸收邪魔虎鲸王魂环后获得的能力之一，攻击时将目标以及周围环境化作晶体凝固，体质羸弱者会被囚困其中，<br> 你使用蓝银草进行的攻击检定命中后，目标需要以强韧豁免对抗伤害出目，若你胜出，则目标陷入持续一轮的A级环境来源的【石化】状态。</p><p>【蓝银虎鲸魔之摄】<br> 吸收邪魔虎鲸王魂环后获得的能力之一，攻击时释放出虎鲸噬人一般的精神冲击，意志薄弱者会当场呆立，<br> 你使用蓝银草进行的攻击检定命中后，目标需要以意志豁免对抗伤害出目，若你胜出，则目标陷入持续一轮的A级影响心灵来源的【震慑】状态。</p><p>【第九魂技】<br> S+9600</p><p>【封号斗罗】<br> 你的实力达到了斗罗大陆的顶峰，现在你可以为自己取一个封号了，<br> 你的【魂力】能量池恢复无上限，每轮额外获得4点AP，仅能用于施展蓝银草相关技艺。<br> 你免疫B级及以下的【胁迫】、【支配】、【思维控制】、【解析】、【预知】、【读心】效果。</p><p>【蓝银天青龙之魂】<br> 吸收天青牛蟒魂环后获得的能力之一，蓝银草化作龙形，附着龙魂强攻敌人<br> 取代【蓝银霸王枪】攻击方式，以一个标准动作消耗2点魂力，你对敏感范围内的所有敌人进行一次攻击，此次攻击附带S级附身来源的【扼魂】效果，正常豁免，持续一轮，这次攻击造成韧性伤害，且最终伤害翻倍，<br> 命中后，敌人需要以反射豁免对抗伤害出目，若失败，则使目标的【反射豁免】获得【劣化3】，这是一个S级创伤来源的效果，持续一轮，并且你可以以一个自由动作对敌人进行一次拖拽，此次拖拽过程中无视体积带来的优势或劣势。</p><p>【蓝银青龙缠之韧】<br> 吸收天青牛蟒魂环后获得的能力之一，所有魂环技能中最强大的控制技能。<br> 你对蓝银草攻击检定命中后，目标以反射豁免对抗伤害出目，若你胜出，则目标陷入S级附身来源的【S级困难地形】状态，并且无法使用S级及以下的【传送】类效果，目标还会陷入A级重伤状态，持续一场景。</p><hr><p>Copyright ? 2025 <a href="http://www.goddessfantasy.net/bbs/index.php?board=2008.0" target="_blank" rel="noreferrer">TMDtrpg制作组</a>. All Rights Reserved.</p>',44)])])}const f=p(s,[["render",o]]);export{m as __pageData,f as default};
